parameters.jsCode:
const source = $('Code — Clean & Extract Content').item.json;
const rawContent = $input.item.json.content[0].text;

let repurposed;
try {
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  repurposed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  repurposed = { parse_error: true, raw: rawContent };
}

const linkedin_post = repurposed.linkedin
  ? `${repurposed.linkedin.hook}\n\n${repurposed.linkedin.body}\n\n${repurposed.linkedin.cta}\n\n${(repurposed.linkedin.hashtags || []).join(' ')}`
  : '';

const twitter_thread = repurposed.twitter?.thread
  ? repurposed.twitter.thread.join('\n---\n')
  : '';

return {
  // Source metadata
  original_title: source.title,
  original_url: source.url,
  original_author: source.author,
  published_at: source.published_at,
  word_count: source.word_count,

  // LinkedIn
  linkedin_hook: repurposed.linkedin?.hook || '',
  linkedin_body: repurposed.linkedin?.body || '',
  linkedin_cta: repurposed.linkedin?.cta || '',
  linkedin_hashtags: (repurposed.linkedin?.hashtags || []).join(' '),
  linkedin_full_post: linkedin_post,

  // Twitter/X
  twitter_thread: twitter_thread,
  twitter_tweet_count: repurposed.twitter?.thread?.length || 0,

  // Email
  email_subject: repurposed.email?.subject_line || '',
  email_preview: repurposed.email?.preview_text || '',
  email_body: repurposed.email?.body || '',
  email_cta_text: repurposed.email?.cta_button_text || '',
  email_cta_url: repurposed.email?.cta_url || '',

  // Summary
  article_summary: repurposed.summary || '',

  // Pipeline metadata
  processed_at: new Date().toISOString(),
  pipeline_version: '1.0.0',
  parse_error: repurposed.parse_error || false
};
